53	/** S5a 双基线间隔计算 */
54	function s5aInterval(meta) {
55	  if (meta.customer_type === '样品单') return 3;
56	  if (!meta.transit_days) return 7; // 默认大货交期35天÷5≈7
57	  const interval = Math.round(meta.transit_days / 5);
58	  return Math.max(3, Math.min(10, interval));
59	}
